function useMemo(array) {
  const memo = useRef();
  if (!memo.current || array !== memo.current) {
    memo.current = array;
  }
  return memo.current;
}

function App() {
  const [array, setArray] = useState([]);
  const memoizedArray = useMemo(array);
  return (
    <div>
      {memoizedArray.map((item, index) => (
        <div key={index}>{item.name}</div>
      ))}
    </div>
  );
}

export default App;

